import { CursoService } from '../../../../core/services/curso.service';
import { ModuloService } from '../../../../core/services/modulo.service';
import { CursoRequest, CursoResponse } from '../../../../core/models/curso.model';
import { ModuloRequest, ModuloResponse } from '../../../../core/models/modulo.model';

@Component({
  selector: 'app-curso-detalle',
  standalone: true,
  imports: [
    CommonModule,
    RouterModule,
    FormsModule,
    ReactiveFormsModule
  ],
  templateUrl: './curso-detalle.component.html',
  styleUrls: ['./curso-detalle.component.css']
})
export class CursoDetalleComponent implements OnInit {
  private route = inject(ActivatedRoute);
  private router = inject(Router);
  private cursoService = inject(CursoService);
  private moduloService = inject(ModuloService);
  private fb = inject(FormBuilder);

  cursoId!: number;
  curso: CursoResponse | null = null;
  modulos: ModuloResponse[] = [];

  // Modals
  showModuloModal = false;
  showEditCourseModal = false;
  isEditModuloMode = false;
  isModuloSubmitting = false;
  isCourseSubmitting = false;

  // Selected for edits
  selectedModulo: ModuloResponse | null = null;

  // Errors
  moduloErrorMsg = '';
  courseErrorMsg = '';

  // Forms
  moduloForm: FormGroup = this.fb.group({
    nombre: ['', [Validators.required]],
    descripcion: ['', [Validators.required]],
    orden: [1, [Validators.required, Validators.min(1)]],
    estado: [true]
  });

  courseForm: FormGroup = this.fb.group({
    nombre: ['', [Validators.required]],
    descripcion: ['', [Validators.required]],
    imagenPortada: [''],
    nivelSuscripcionId: [1, [Validators.required]],
    estado: [true]
  });

  ngOnInit(): void {
    this.route.paramMap.subscribe(params => {
      const idParam = params.get('id');
      if (idParam) {
        this.cursoId = Number(idParam);
        this.loadCourseData();
      } else {
        this.router.navigate(['/dashboard/cursos']);
      }
    });
  }

  loadCourseData(): void {
    this.cursoService.obtenerCurso(this.cursoId).subscribe({
      next: (data) => {
        this.curso = data;
        this.loadModulos();
      },
      error: (err) => {
        console.error('Error al obtener curso', err);
        this.router.navigate(['/dashboard/cursos']);
      }
    });
  }

  loadModulos(): void {
    this.moduloService.listarModulosPorCurso(this.cursoId).subscribe({
      next: (data) => {
        this.modulos = data;
      },
      error: (err) => {
        console.error('Error al listar módulos', err);
      }
    });
  }

  // Modulo actions
  openCreateModuloModal(): void {
    this.isEditModuloMode = false;
    this.moduloErrorMsg = '';
    this.selectedModulo = null;
    this.moduloForm.reset({
      nombre: '',
      descripcion: '',
      orden: this.modulos.length + 1,
      estado: true
    });
    this.showModuloModal = true;
  }

  openEditModuloModal(modulo: ModuloResponse): void {
    this.isEditModuloMode = true;
    this.moduloErrorMsg = '';
    this.selectedModulo = modulo;
    this.moduloForm.patchValue({
      nombre: modulo.nombre,
      descripcion: modulo.descripcion,
      orden: modulo.orden,
      estado: modulo.estado
    });
    this.showModuloModal = true;
  }

  closeModuloModal(): void {
    this.showModuloModal = false;
    this.isModuloSubmitting = false;
  }

  toggleModuloEstado(modulo: ModuloResponse): void {
    const nuevoEstado = !modulo.estado;
    this.moduloService.cambiarEstado(modulo.id, nuevoEstado).subscribe({
      next: () => {
        modulo.estado = nuevoEstado;
      },
      error: (err) => {
        console.error('Error al cambiar estado del módulo', err);
      }
    });
  }

  onModuloSubmit(): void {
    if (this.moduloForm.invalid) {
      return;
    }

    this.isModuloSubmitting = true;
    this.moduloErrorMsg = '';

    const req: ModuloRequest = {
      cursoId: this.cursoId,
      nombre: this.moduloForm.value.nombre,
      descripcion: this.moduloForm.value.descripcion,
      orden: Number(this.moduloForm.value.orden)
    };

    if (this.isEditModuloMode && this.selectedModulo) {
      this.moduloService.editarModulo(this.selectedModulo.id, req).subscribe({
        next: () => {
          const stateChanged = this.moduloForm.value.estado !== this.selectedModulo!.estado;
          if (stateChanged) {
            this.moduloService.cambiarEstado(this.selectedModulo!.id, this.moduloForm.value.estado).subscribe({
              next: () => {
                this.loadModulos();
                this.closeModuloModal();
              },
              error: (err) => this.handleModuloError(err)
            });
          } else {
            this.loadModulos();
            this.closeModuloModal();
          }
        },
        error: (err) => this.handleModuloError(err)
      });
    } else {
      this.moduloService.crearModulo(req).subscribe({
        next: () => {
          this.loadModulos();
          this.closeModuloModal();
        },
        error: (err) => this.handleModuloError(err)
      });
    }
  }

  private handleModuloError(err: any): void {
    this.isModuloSubmitting = false;
    this.moduloErrorMsg = err.error?.message || 'Error al procesar el módulo.';
  }

  // Course edit actions
  openEditCourseModal(): void {
    if (!this.curso) return;
    this.courseErrorMsg = '';

    let subId = 1;
    if (this.curso.nivelSuscripcion === 'INTERMEDIO') {
      subId = 2;
    } else if (this.curso.nivelSuscripcion === 'PREMIUM') {
      subId = 3;
    }

    this.courseForm.patchValue({
      nombre: this.curso.nombre,
      descripcion: this.curso.descripcion,
      imagenPortada: this.curso.imagenPortada,
      nivelSuscripcionId: subId,
      estado: this.curso.estado
    });
    this.showEditCourseModal = true;
  }

  closeEditCourseModal(): void {
    this.showEditCourseModal = false;
    this.isCourseSubmitting = false;
  }

  onCourseSubmit(): void {
    if (this.courseForm.invalid || !this.curso) {
      return;
    }

    this.isCourseSubmitting = true;
    this.courseErrorMsg = '';

    const req: CursoRequest = {
      nombre: this.courseForm.value.nombre,
      descripcion: this.courseForm.value.descripcion,
      imagenPortada: this.courseForm.value.imagenPortada || '',
      nivelSuscripcionId: Number(this.courseForm.value.nivelSuscripcionId)
    };

    this.cursoService.editarCurso(this.cursoId, req).subscribe({
      next: () => {
        const stateChanged = this.courseForm.value.estado !== this.curso!.estado;
        if (stateChanged) {
          this.cursoService.cambiarEstado(this.cursoId, this.courseForm.value.estado).subscribe({
            next: () => {
              this.loadCourseData();
              this.closeEditCourseModal();
            },
            error: (err) => this.handleCourseError(err)
          });
        } else {
          this.loadCourseData();
          this.closeEditCourseModal();
        }
      },
      error: (err) => this.handleCourseError(err)
    });
  }

  private handleCourseError(err: any): void {
    this.isCourseSubmitting = false;
    this.courseErrorMsg = err.error?.message || 'Error al actualizar el curso.';
  }

  getSubscriptionClass(sub: string): string {
    switch (sub) {
      case 'PREMIUM':
        return 'bg-[#f9e37a]/20 text-[#6d5e00] border border-[#f9e37a]/60';
      case 'INTERMEDIO':
        return 'bg-blue-50 text-blue-700 border border-blue-200';
      case 'BASICO':
      default:
        return 'bg-slate-50 text-slate-700 border border-slate-200';
    }
  }
}
<div class="space-y-8 font-body" *ngIf="curso">

  <!-- Back button -->
  <div class="flex items-center">
    <a 
      routerLink="/dashboard/cursos" 
      class="flex items-center gap-1.5 text-xs font-bold text-slate-500 hover:text-slate-900 uppercase tracking-widest transition-colors">
      <span class="material-symbols-outlined text-sm">arrow_back</span>
      <span>Volver a Cursos</span>
    </a>
  </div>

  <!-- Course Header Banner: Squared & Structured -->
  <div class="border border-slate-200 bg-white rounded-none shadow-[4px_4px_0px_0px_rgba(15,23,42,0.05)] overflow-hidden">
    <!-- Banner Image / Header background -->
    <div class="h-48 bg-slate-900 border-b border-slate-200 overflow-hidden relative">
      <img 
        *ngIf="curso.imagenPortada" 
        [src]="curso.imagenPortada" 
        [alt]="curso.nombre" 
        class="w-full h-full object-cover opacity-60">
      <div *ngIf="!curso.imagenPortada" class="w-full h-full bg-gradient-to-r from-slate-900 via-slate-800 to-slate-950 opacity-80"></div>

      <!-- Overlay Header Content -->
      <div class="absolute inset-0 p-8 flex flex-col justify-end text-white bg-gradient-to-t from-black/80 to-transparent">
        <div class="flex flex-wrap items-center gap-3">
          <span [ngClass]="getSubscriptionClass(curso.nivelSuscripcion)" class="px-2.5 py-0.5 text-[9px] font-black uppercase tracking-wider rounded-none">
            {{ curso.nivelSuscripcion }}
          </span>
          <span [ngClass]="curso.estado ? 'bg-emerald-600/30 text-emerald-300 border-emerald-500/40' : 'bg-red-600/30 text-red-300 border-red-500/40'" class="px-2.5 py-0.5 text-[9px] font-black uppercase tracking-wider border rounded-none">
            {{ curso.estado ? 'Activo' : 'Inactivo' }}
          </span>
        </div>
        <h1 class="text-3xl font-black mt-2 tracking-tight uppercase leading-none">{{ curso.nombre }}</h1>
        <p class="text-slate-300 text-xs mt-1.5 max-w-2xl truncate">{{ curso.descripcion }}</p>
      </div>
    </div>

    <!-- Actions Toolbar -->
    <div class="px-8 py-4 bg-slate-50 flex flex-wrap justify-between items-center gap-4">
      <span class="text-[10px] font-bold text-slate-400 uppercase tracking-widest">
        Administración Curricular
      </span>
      <div class="flex gap-3">
        <button 
          (click)="openEditCourseModal()" 
          class="flex items-center gap-2 px-4 py-2 border border-slate-300 bg-white hover:bg-slate-100 text-slate-800 font-bold text-xs uppercase tracking-widest transition-colors rounded-none">
          <span class="material-symbols-outlined text-sm">edit</span>
          <span>Editar Curso</span>
        </button>
        <button 
          (click)="openCreateModuloModal()" 
          class="flex items-center gap-2 px-4 py-2 bg-slate-900 text-white hover:bg-slate-800 font-bold text-xs uppercase tracking-widest transition-colors rounded-none">
          <span class="material-symbols-outlined text-sm">add</span>
          <span>Agregar Módulo</span>
        </button>
      </div>
    </div>
  </div>

  <!-- Modules Grid Section -->
  <div class="space-y-6">
    <div class="flex items-center justify-between border-b border-slate-200 pb-3">
      <h2 class="text-base font-black text-slate-900 uppercase tracking-wider flex items-center gap-2">
        <span class="material-symbols-outlined text-primary text-xl">view_module</span>
        <span>Estructura de Módulos</span>
      </h2>
      <span class="text-[10px] font-bold text-slate-400 uppercase tracking-widest">
        {{ modulos.length }} Módulos en total
      </span>
    </div>

    <!-- Empty State -->
    <div *ngIf="modulos.length === 0" class="border border-slate-200 p-16 bg-white text-center rounded-none shadow-[4px_4px_0px_0px_rgba(15,23,42,0.05)]">
      <span class="material-symbols-outlined text-5xl text-slate-300 mb-3">folder_zip</span>
      <h3 class="text-sm font-bold text-slate-800 uppercase tracking-wider">Sin Módulos</h3>
      <p class="text-xs text-slate-500 mt-1 max-w-sm mx-auto leading-relaxed">Este curso todavía no contiene módulos organizados. Haz click en "Agregar Módulo" para comenzar a estructurar el contenido.</p>
    </div>

    <!-- Cards Grid -->
    <div *ngIf="modulos.length > 0" class="grid grid-cols-1 md:grid-cols-3 gap-6">
      <div 
        *ngFor="let modulo of modulos" 
        class="border border-slate-200 bg-white p-6 rounded-none shadow-[4px_4px_0px_0px_rgba(15,23,42,0.05)] flex flex-col justify-between h-64 relative group">

        <!-- Status Indicator Strip -->
        <div [ngClass]="modulo.estado ? 'bg-emerald-500' : 'bg-red-400'" class="absolute left-0 top-0 bottom-0 w-1"></div>

        <div>
          <!-- Module Header -->
          <div class="flex items-center justify-between border-b border-slate-100 pb-2.5">
            <span class="text-[10px] font-black text-primary uppercase tracking-widest">Módulo {{ modulo.orden }}</span>
            <span [ngClass]="modulo.estado ? 'text-emerald-700' : 'text-red-500'" class="text-[9px] font-bold uppercase tracking-wider">
              {{ modulo.estado ? 'Activo' : 'Inactivo' }}
            </span>
          </div>

          <!-- Module Title & Desc -->
          <div class="mt-4">
            <h3 class="text-sm font-black text-slate-900 uppercase leading-snug tracking-tight truncate">{{ modulo.nombre }}</h3>
            <p class="text-[11px] text-slate-500 mt-1.5 leading-relaxed line-clamp-3">{{ modulo.descripcion }}</p>
          </div>
        </div>

        <div>
          <!-- Module Stats (Prepared for Sprint 5) -->
          <div class="grid grid-cols-2 gap-2 border-t border-slate-100 pt-4 mb-4 text-[10px] font-bold text-slate-400 uppercase tracking-wider">
            <div class="flex items-center gap-1.5">
              <span class="material-symbols-outlined text-sm text-slate-400">videocam</span>
              <span>Videos: 0</span>
            </div>
            <div class="flex items-center gap-1.5">
              <span class="material-symbols-outlined text-sm text-slate-400">description</span>
              <span>Materiales: 0</span>
            </div>
          </div>

          <!-- Action buttons inside Card -->
          <div class="grid grid-cols-2 gap-2">
            <button 
              (click)="openEditModuloModal(modulo)" 
              class="py-1.5 border border-slate-200 hover:border-slate-400 bg-white text-slate-700 font-bold text-[10px] uppercase tracking-wider transition-colors text-center rounded-none">
              Editar
            </button>
            <button 
              (click)="toggleModuloEstado(modulo)" 
              [ngClass]="modulo.estado ? 'border-red-200 text-red-600 hover:bg-red-50' : 'border-emerald-200 text-emerald-600 hover:bg-emerald-50'"
              class="py-1.5 border font-bold text-[10px] uppercase tracking-wider transition-colors text-center rounded-none">
              {{ modulo.estado ? 'Desactivar' : 'Activar' }}
            </button>
            <a 
              [routerLink]="['/dashboard/modulos', modulo.id, 'videos']"
              class="py-1.5 border border-slate-200 hover:border-slate-400 bg-white text-slate-700 font-bold text-[10px] uppercase tracking-wider transition-colors text-center rounded-none flex items-center justify-center">
              Videos
            </a>
            <a 
              [routerLink]="['/dashboard/modulos', modulo.id, 'materiales']"
              class="py-1.5 border border-slate-200 hover:border-slate-400 bg-white text-slate-700 font-bold text-[10px] uppercase tracking-wider transition-colors text-center rounded-none flex items-center justify-center">
              Materiales
            </a>
          </div>
        </div>
      </div>
    </div>
  </div>

  <!-- Create/Edit Modulo Modal -->
  <div *ngIf="showModuloModal" class="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-50 flex items-center justify-center p-4">
    <div class="w-full max-w-md bg-white border border-slate-200 shadow-2xl rounded-none overflow-hidden relative">
      <!-- Modal Header -->
      <div class="px-6 py-4 border-b border-slate-200 bg-slate-50 flex items-center justify-between">
        <h3 class="text-sm font-black text-slate-900 uppercase tracking-wider">
          {{ isEditModuloMode ? 'Editar Módulo' : 'Registrar Nuevo Módulo' }}
        </h3>
        <button (click)="closeModuloModal()" class="text-slate-400 hover:text-slate-600">
          <span class="material-symbols-outlined text-lg">close</span>
        </button>
      </div>

      <!-- Modal Form -->
      <form [formGroup]="moduloForm" (ngSubmit)="onModuloSubmit()" class="p-6 space-y-4">
        <div *ngIf="moduloErrorMsg" class="flex items-start gap-2 bg-red-50 border border-red-200 text-red-800 p-3 rounded-none text-[11px] font-semibold">
          <span class="material-symbols-outlined text-red-600 text-base">warning</span>
          <span>{{ moduloErrorMsg }}</span>
        </div>

        <!-- Nombre -->
        <div>
          <label class="block text-[10px] font-bold text-slate-700 mb-1 uppercase tracking-widest">Nombre del Módulo *</label>
          <input 
            formControlName="nombre" 
            type="text" 
            class="w-full px-3 py-2 border border-slate-300 bg-white text-slate-900 text-xs rounded-none focus:outline-none focus:ring-1 focus:ring-primary focus:border-primary"
            placeholder="Ej. Conceptos Fundamentales">
          <p *ngIf="moduloForm.get('nombre')?.invalid && moduloForm.get('nombre')?.touched" class="text-[10px] text-red-600 mt-1">El nombre es obligatorio.</p>
        </div>

        <!-- Descripcion -->
        <div>
          <label class="block text-[10px] font-bold text-slate-700 mb-1 uppercase tracking-widest">Descripción *</label>
          <textarea 
            formControlName="descripcion" 
            rows="3" 
            class="w-full px-3 py-2 border border-slate-300 bg-white text-slate-900 text-xs rounded-none focus:outline-none focus:ring-1 focus:ring-primary focus:border-primary"
            placeholder="Escribe una breve descripción del temario de este módulo..."></textarea>
          <p *ngIf="moduloForm.get('descripcion')?.invalid && moduloForm.get('descripcion')?.touched" class="text-[10px] text-red-600 mt-1">La descripción es obligatoria.</p>
        </div>

        <div class="grid grid-cols-2 gap-4">
          <!-- Orden -->
          <div>
            <label class="block text-[10px] font-bold text-slate-700 mb-1 uppercase tracking-widest">Orden *</label>
            <input 
              formControlName="orden" 
              type="number" 
              class="w-full px-3 py-2 border border-slate-300 bg-white text-slate-900 text-xs rounded-none focus:outline-none focus:ring-1 focus:ring-primary focus:border-primary">
            <p *ngIf="moduloForm.get('orden')?.invalid && moduloForm.get('orden')?.touched" class="text-[10px] text-red-600 mt-1">El orden es requerido.</p>
          </div>
          <!-- Estado (Edit Mode only) -->
          <div>
            <label class="block text-[10px] font-bold text-slate-700 mb-1 uppercase tracking-widest">Estado</label>
            <select 
              formControlName="estado" 
              class="w-full px-3 py-2 border border-slate-300 bg-white text-slate-900 text-xs rounded-none focus:outline-none focus:ring-1 focus:ring-primary focus:border-primary">
              <option [ngValue]="true">ACTIVO</option>
              <option [ngValue]="false">INACTIVO</option>
            </select>
          </div>
        </div>

        <!-- Form Buttons -->
        <div class="pt-4 border-t border-slate-100 flex justify-end gap-3">
          <button 
            type="button" 
            (click)="closeModuloModal()" 
            class="px-4 py-2 border border-slate-300 bg-white text-slate-700 font-bold text-xs uppercase tracking-widest hover:bg-slate-50 transition-colors rounded-none">
            Cancelar
          </button>
          <button 
            type="submit" 
            [disabled]="moduloForm.invalid || isModuloSubmitting" 
            class="px-4 py-2 bg-slate-900 text-white font-bold text-xs uppercase tracking-widest hover:bg-slate-800 transition-colors rounded-none disabled:opacity-55">
            {{ isModuloSubmitting ? 'Guardando...' : 'Guardar Módulo' }}
          </button>
        </div>
      </form>
    </div>
  </div>

  <!-- Edit Course Modal (Reused inside details) -->
  <div *ngIf="showEditCourseModal" class="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-50 flex items-center justify-center p-4">
    <div class="w-full max-w-lg bg-white border border-slate-200 shadow-2xl rounded-none overflow-hidden relative">
      <!-- Modal Header -->
      <div class="px-6 py-4 border-b border-slate-200 bg-slate-50 flex items-center justify-between">
        <h3 class="text-sm font-black text-slate-900 uppercase tracking-wider">Modificar Curso</h3>
        <button (click)="closeEditCourseModal()" class="text-slate-400 hover:text-slate-600">
          <span class="material-symbols-outlined text-lg">close</span>
        </button>
      </div>

      <!-- Modal Form -->
      <form [formGroup]="courseForm" (ngSubmit)="onCourseSubmit()" class="p-6 space-y-4">
        <div *ngIf="courseErrorMsg" class="flex items-start gap-2 bg-red-50 border border-red-200 text-red-800 p-3 rounded-none text-[11px] font-semibold">
          <span class="material-symbols-outlined text-red-600 text-base">warning</span>
          <span>{{ courseErrorMsg }}</span>
        </div>

        <!-- Nombre -->
        <div>
          <label class="block text-[10px] font-bold text-slate-700 mb-1 uppercase tracking-widest">Nombre del Curso *</label>
          <input 
            formControlName="nombre" 
            type="text" 
            class="w-full px-3 py-2 border border-slate-300 bg-white text-slate-900 text-xs rounded-none focus:outline-none focus:ring-1 focus:ring-primary focus:border-primary">
          <p *ngIf="courseForm.get('nombre')?.invalid && courseForm.get('nombre')?.touched" class="text-[10px] text-red-600 mt-1">El nombre del curso es requerido.</p>
        </div>

        <!-- Descripcion -->
        <div>
          <label class="block text-[10px] font-bold text-slate-700 mb-1 uppercase tracking-widest">Descripción *</label>
          <textarea 
            formControlName="descripcion" 
            rows="3" 
            class="w-full px-3 py-2 border border-slate-300 bg-white text-slate-900 text-xs rounded-none focus:outline-none focus:ring-1 focus:ring-primary focus:border-primary"></textarea>
          <p *ngIf="courseForm.get('descripcion')?.invalid && courseForm.get('descripcion')?.touched" class="text-[10px] text-red-600 mt-1">La descripción es requerida.</p>
        </div>

        <!-- Imagen Portada URL -->
        <div>
          <label class="block text-[10px] font-bold text-slate-700 mb-1 uppercase tracking-widest">URL Imagen de Portada</label>
          <input 
            formControlName="imagenPortada" 
            type="text" 
            class="w-full px-3 py-2 border border-slate-300 bg-white text-slate-900 text-xs rounded-none focus:outline-none focus:ring-1 focus:ring-primary focus:border-primary">
        </div>

        <div class="grid grid-cols-1 md:grid-cols-2 gap-4">
          <!-- Nivel de suscripcion -->
          <div>
            <label class="block text-[10px] font-bold text-slate-700 mb-1 uppercase tracking-widest">Nivel de Suscripción *</label>
            <select 
              formControlName="nivelSuscripcionId" 
              class="w-full px-3 py-2 border border-slate-300 bg-white text-slate-900 text-xs rounded-none focus:outline-none focus:ring-1 focus:ring-primary focus:border-primary">
              <option [value]="1">BÁSICO</option>
              <option [value]="2">INTERMEDIO</option>
              <option [value]="3">PREMIUM</option>
            </select>
          </div>
          <!-- Estado -->
          <div>
            <label class="block text-[10px] font-bold text-slate-700 mb-1 uppercase tracking-widest">Estado</label>
            <select 
              formControlName="estado" 
              class="w-full px-3 py-2 border border-slate-300 bg-white text-slate-900 text-xs rounded-none focus:outline-none focus:ring-1 focus:ring-primary focus:border-primary">
              <option [ngValue]="true">ACTIVO</option>
              <option [ngValue]="false">INACTIVO</option>
            </select>
          </div>
        </div>

        <!-- Form Buttons -->
        <div class="pt-4 border-t border-slate-100 flex justify-end gap-3">
          <button 
            type="button" 
            (click)="closeEditCourseModal()" 
            class="px-4 py-2 border border-slate-300 bg-white text-slate-700 font-bold text-xs uppercase tracking-widest hover:bg-slate-50 transition-colors rounded-none">
            Cancelar
          </button>
          <button 
            type="submit" 
            [disabled]="courseForm.invalid || isCourseSubmitting" 
            class="px-4 py-2 bg-slate-900 text-white font-bold text-xs uppercase tracking-widest hover:bg-slate-800 transition-colors rounded-none disabled:opacity-55">
            {{ isCourseSubmitting ? 'Guardando...' : 'Guardar Cambios' }}
          </button>
        </div>
      </form>
    </div>
  </div>

</div>
